def analyze_conversation_state(history):
    tool_patterns = []
    for i, msg in enumerate(history[-20:]):
        if msg.type == 'tool_use':
            tool_patterns.append({
                'turn': i,
                'tool': msg.name,
                'input_hash': hash(str(msg.input))
            })

    # Detect cycles (same tool+input within 5 turns)
    for i, pattern in enumerate(tool_patterns):
        for j in range(i+1, min(i+6, len(tool_patterns))):
            if (pattern['tool'] == tool_patterns[j]['tool'] and 
                pattern['input_hash'] == tool_patterns[j]['input_hash']):
                return True
    return False

interface ToolUse { name: string; input: any; }

function detectTokenLoop(messages: any[], tokenBudget: number = 10000): boolean {
  let toolTokens = 0;
  const recentTools = new Map<string, number>();

  for (let i = Math.max(0, messages.length - 15); i < messages.length; i++) {
    const msg = messages[i];
    if (msg.content?.[0]?.type === 'tool_use') {
      const tool = msg.content[0] as ToolUse;
      const key = `${tool.name}:${JSON.stringify(tool.input)}`;
      recentTools.set(key, (recentTools.get(key) || 0) + 1);
      toolTokens += 200; // Estimate per tool call
    }
  }

  return toolTokens > tokenBudget * 0.8 ||
         Array.from(recentTools.values()).some(count => count >= 4);
}

