class ToolLoopGuard:
    def __init__(self):
        self.recent_calls = {}

    def check_tool(self, tool_name, tool_input):
        key = f'{tool_name}:{str(tool_input)}'
        now = time.time()
        if key in self.recent_calls:
            if now - self.recent_calls[key] < 30:  # 30s cooldown
                return False
        self.recent_calls[key] = now
        return True

