loop_guard = ToolLoopGuard()

def safe_tool_use(client, messages, tools):
    response = client.messages.create(
        model='claude-3-5-sonnet-20240620',
        messages=messages,
        tools=tools,
        extra_headers={'anthropic-beta': 'tools-2024-06-20'}
    )

    if response.content[0].type == 'tool_use':
        tool = response.content[0]
        if not loop_guard.check_tool(tool.name, tool.input):
            return {'content': [{'type': 'text', 'text': 'Tool call blocked to prevent loop'}]}
    return response

const toolThrottle = new Map<string, number>();
const MAX_CALLS = 3;

const throttledToolCall = (toolName: string, input: any): boolean => {
  const key = `${toolName}:${JSON.stringify(input)}`;
  const now = Date.now();
  const calls = toolThrottle.get(key) || 0;

  if (calls >= MAX_CALLS) {
    console.warn(`Tool loop blocked: ${key}`);
    return false;
  }

  toolThrottle.set(key, calls + 1);
  setTimeout(() => {
    const remaining = (toolThrottle.get(key) || 0) - 1;
    if (remaining <= 0) toolThrottle.delete(key);
    else toolThrottle.set(key, remaining);
  }, 30000);

  return true;
};

